#include<bits/stdc++.h>
using namespace std;
int c,n,m,q;
int x[500010],y[500010],a[500010],b[500010],u[500010],v[500010],dp[2020][2020];
struct node
{
    int max1,min1,maxid,minid;
}lx[500010],rx[500010],ly[500010],ry[500010];
node f(node c,int b,int id)
{
    if(b>c.max1)
    {
        c.max1=b;
        c.maxid=id;
    }
    if(b<c.min1)
    {
        c.min1=b;
        c.minid=id;
    }
    return c;
}
bool dfs1(int x,int y,int tx,int ty)
{
    if(x==tx||y==ty)
    {
        return true;
    }
    node u=lx[x-1],v=ly[y-1];
    if(u.max1<v.max1)
    {
        return dfs1(x,v.maxid,tx,ty);
    }
    if(u.min1<v.min1)
    {
        return dfs1(u.minid,y,tx,ty);
    }
    return false;
}
bool dfs2(int x,int y,int tx,int ty)
{
    if(x==tx||y==ty)
    {
        return true;
    }
    node u=rx[x+1],v=ry[y+1];
    if(u.max1<v.max1)
    {
        return dfs2(x,v.maxid,tx,ty);
    }
    if(u.min1<v.min1)
    {
        return dfs2(u.minid,y,tx,ty);
    }
    return false;
}
bool check(int x[],int y[],int n,int m)
{
    if(x[1]>=y[1])
    {
        return false;
    }
    for(int i=1;i<=n;i++)
    {
        a[i]=x[i];
    }
    for(int i=1;i<=m;i++)
    {
        b[i]=y[i];
    }
    lx[1].max1=lx[1].min1=a[1];
    ly[1].max1=ly[1].min1=b[1];
    lx[1].maxid=ly[1].maxid=lx[1].minid=ly[1].minid=1;
    for(int i=2;i<=n;i++)
    {
        lx[i]=f(lx[i-1],a[i],i);
    }
    for(int i=2;i<=m;i++)
    {
        ly[i]=f(ly[i-1],b[i],i);
    }
    rx[n].max1=rx[n].min1=a[n];
    ry[m].max1=ry[m].min1=b[m];
    rx[n].maxid=rx[n].minid=n;
    ry[m].maxid=ry[m].minid=m;
    for(int i=n-1;i>=1;i--)
    {
        rx[i]=f(rx[i+1],a[i],i);
    }
    for(int i=m-1;i>=1;i--)
    {
        ry[i]=f(ry[i+1],b[i],i);
    }
    node u=lx[n],v=ly[m];
    if(u.min1>=v.min1||v.max1<=u.max1)
    {
        return false;
    }
    return dfs1(u.minid,v.maxid,1,1)&&dfs2(u.minid,v.maxid,n,m);
}
int main()
{
    scanf("%d%d%d%d",&c,&n,&m,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&x[i]);
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&y[i]);
    }
    printf("%d",(int)(check(x,y,n,m)||check(y,x,m,n)));
    while(q--)
    {
        memcpy(u,x,sizeof(x));
        memcpy(v,y,sizeof(y));
        int kx,ky;
        scanf("%d%d",&kx,&ky);
        for(int i=1;i<=kx;i++)
        {
            int px,vx;
            scanf("%d%d",&px,&vx);
            u[px]=vx;
        }
        for(int i=1;i<=ky;i++)
        {
            int py,vy;
            scanf("%d%d",&py,&vy);
            v[py]=vy;
        }
        printf("%d",(int)(check(u,v,n,m)||check(v,u,m,n)));
    }
    return 0;
}
